      .filter(c => c.visible)
      .map(c => c.value)
      .join('')
  }

  findInsertIndex(id) {
    // Binary search to find position based on ID ordering
    // IDs are ordered by (position, siteId)
    let left = 0, right = this.chars.length

    while (left < right) {
      const mid = Math.floor((left + right) / 2)
      if (this.compareIds(this.chars[mid].id, id) < 0) {
        left = mid + 1
      } else {
        right = mid
      }
    }
    return left
  }

  compareIds(id1, id2) {
    if (id1.position !== id2.position) {
      return id1.position - id2.position
    }
    return id1.siteId.localeCompare(id2.siteId)
  }

  idEquals(id1, id2) {
    return id1.position === id2.position && id1.siteId === id2.siteId
  }
}

// Usage
const doc1 = new SimpleCRDT('user1')
const doc2 = new SimpleCRDT('user2')

// User 1 types "Hello"
const op1 = doc1.localInsert(0, 'H')
const op2 = doc1.localInsert(1, 'e')

// Simulate network: send operations to user 2
doc2.remoteInsert(op1)
doc2.remoteInsert(op2)

console.log(doc1.toString()) // "He"
console.log(doc2.toString()) // "He" - converged!
```

## Architecture Comparison

### CRDT Architecture (Simpler)
```
Client A ─┐
          ├─→ WebSocket Server (just broadcasts) ─→ All Clients
Client B ─┘

- Server is dumb relay
- Clients do all merge logic
- Works offline, syncs later
```

### OT Architecture (More Complex)
```
Client A ─┐
          ├─→ Central Server (transforms operations) ─→ All Clients
Client B ─┘

- Server must maintain operation history
- Server transforms conflicting operations
- Requires constant connection
```

## My Recommendation for Your Team

**Use Yjs** because:

1. **Time to market:** You'll have working collaboration in days, not months
2. **Correctness:** Battle-tested library vs. rolling your own OT (which will have bugs)
3. **Features:** Yjs includes awareness (cursors), undo/redo, offline support out of the box
4. **Scalability:** Good enough for small-to-medium documents (thousands of users)

Only consider OT if:
- You're building the next Google Docs with millions of users
- You have 6+ months and distributed systems experts
- You need absolute minimal bandwidth usage

**Start simple, scale later.** You can always optimize once you have users.
